import boto3

def lambda_handler(event, context):
    sns = boto3.client('sns')
    
    message_content = event.get('message', '')
    topic_arn = event.get('topic_arn', '')
    
    if not message_content or not topic_arn:
        return {
            'statusCode': 400,
            'body': 'Message content and topic ARN are required'
        }
    
    response = sns.publish(
        TopicArn=topic_arn,
        Message=message_content
    )
    
    return {
        'statusCode': 200,
        'body': f'Message published to {topic_arn}'
    }